import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

import org.owasp.html.PolicyFactory;
import org.owasp.html.Sanitizers;

public class XSSSecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        out.println("<html>");
        out.println("<head><title>XSS Secure Page</title></head>");
        out.println("<body>");

        // Sanitize user input before displaying it
        PolicyFactory policy = Sanitizers.FORMATTING.and(Sanitizers.LINKS);
        String sanitizedInput = policy.sanitize(userInput);

        out.println("<p>User Input: " + sanitizedInput + "</p>");

        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
